# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit
import MobileCoreServices
import SafariServices

class AppURLProtocolDelegate: NSObject, UITextInputTraits, UIMenuControllerDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIRestorationCallback]) -> Void) -> Bool {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb {
            if let url = userActivity.webpageURL, url.absoluteString.contains("reset-password") {
                guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else { return false }
                if let token = components.queryItems?.first(where: { $0.name == "token" }), let tokenValue = token.value {
                    // Navigate to PasswordResetViewController and pass the token as a parameter
                    let storyboard = UIStoryboard(name: "Main", bundle: nil)
                    if let passwordResetVC = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController {
                        passwordResetVC.token = tokenValue
                        application.keyWindow?.rootViewController?.present(passwordResetVC, animated: true, completion: nil)
                    }
                }
            }
        }
        return false
    }
}

func canOpenURL(_ url: URL) -> Bool {
    let uttypes = [kUTTypeURL as String]
    let itemProviders = [NSItemProvider(url: url)]
    let activityViewController = UIActivityViewController(activityItems: itemProviders, applicationActivities: nil)
    if let popoverController = activityViewController.popoverPresentationController {
        popoverController.sourceView = self.view // or any UIView you want as a source view
    }
    return activityViewController.canPerformAction(forItemAt: url, withActivityType: nil, toOtherActivities: uttypes, withCompletionHandler: nil)
}

let applicationDelegate = UIApplication.shared.delegate as! AppDelegate
applicationDelegate.applicationItemsProviderAdopters += [self]